+  /** Current breakpoint name */
+  breakpoint: Breakpoint;
+  /** Window width in pixels */
+  width: number;
+  /** Window height in pixels */
+  height: number;
+  /** Is mobile viewport (< 768px) */
+  isMobile: boolean;
