+  breakpoint: 'lg',
+  width: 1024,
+  height: 768,
+  isMobile: false,
+  isTablet: false,
+  isDesktop: true,
+  isTouch: false,
+  isPortrait: false,
+  isLandscape: true,
+  prefersReducedMotion: false,
+  prefersDarkMode: false,
+};
